import sys

def query(i, j):
    print(f"? {i} {j}", flush=True)
    r = int(input())
    if r == -1:
        sys.exit(0)
    return r

cache = {}

def q(i, j):
    if (i,j) not in cache:
        cache[(i,j)] = query(i, j)
    return cache[(i,j)]

# Binary search for x1: smallest x where f(x,1) == f(x+1,1) or f(x,1) < f(x-1,1) stops
# f(a,1) decreasing means a < x1, flat/increasing means a >= x1
# f(a,1) - f(a+1,1) = 1 if a < x1, 0 if x1<=a<=x2, -1 if a>x2

def find_x1():
    lo, hi = 1, 10**9 - 1
    while lo < hi:
        mid = (lo + hi) // 2
        if q(mid, 1) > q(mid+1, 1):
            lo = mid + 1
        else:
            hi = mid
    return lo

def find_x2():
    lo, hi = 1, 10**9 - 1
    while lo < hi:
        mid = (lo + hi) // 2
        if q(mid+1, 1) > q(mid, 1):
            hi = mid
        else:
            lo = mid + 1
    return lo

x1 = find_x1()
x2 = find_x2()

# Now find y1, y2 using x=1
def find_y1():
    lo, hi = 1, 10**9 - 1
    while lo < hi:
        mid = (lo + hi) // 2
        if q(1, mid) > q(1, mid+1):
            lo = mid + 1
        else:
            hi = mid
    return lo

def find_y2():
    lo, hi = 1, 10**9 - 1
    while lo < hi:
        mid = (lo + hi) // 2
        if q(1, mid+1) > q(1, mid):
            hi = mid
        else:
            lo = mid + 1
    return lo

y1 = find_y1()
y2 = find_y2()

print(f"! {x1} {y1} {x2} {y2}", flush=True)

